31	/*!
32	 * \brief Paged key-value cache
33	 * \tparam layout The layout of last 3 dimensions in KV-Cache.
34	 * \tparam DType The data type of the key-value cache
35	 * \tparam IdType The index data type of the kv-cache
36	 */
37	template <typename DType, typename IdType>
38	struct paged_kv_t {
39	  uint_fastdiv page_size;
40	  uint32_t num_heads;
41	  uint32_t head_dim;
42	  uint32_t batch_size;
43	  uint32_t stride_page;
44	  uint32_t stride_n;
45	  uint32_t stride_h;
46	
47	  // Internal layout:
48	  // [max_num_pages, num_heads, page_size, head_dim] if layout == HND
49	  // [max_num_pages, page_size, num_heads, head_dim] if layout == NHD
50	  DType* k_data;
51	  DType* v_data;
52	  IdType* indices;
53	
54	  // [batch_size + 1] The page indptr array, with the first element 0, the last element nnz_pages
55	  IdType* indptr;
56	  // [batch_size] The offset of the last page for each request in the batch
57	  IdType* last_page_len;
58	  // [batch_size] The start position of each request in the batch.
59	  IdType* rope_pos_offset;
60	
61	  /*!
62	   * \brief Construct an empty paged key-value cache
63	   */
64	  __host__ __device__ __forceinline__ paged_kv_t()
65	      : num_heads(0),
66	        page_size(),
67	        head_dim(0),
68	        batch_size(0),
69	        stride_page(0),
70	        stride_n(0),
71	        stride_h(0),
72	        k_data(nullptr),
73	        v_data(nullptr),
74	        indices(nullptr),
75	        indptr(nullptr),
76	        last_page_len(nullptr),
77	        rope_pos_offset(nullptr) {}
78	
79	  /*!
80	   * \brief Construct a paged key-value cache
81	   * \param num_heads The number of heads
82	   * \param page_size The size of each page
83	   * \param head_dim The dimension of each head
84	   * \param batch_size The batch size
85	   * \param layout The layout of last 3 dimensions in KV-Cache.
86	   * \param k_data The start pointer of key cache, k_cache should be contiguous
87	   * \param v_data The start pointer of value cache, v_cache should be contiguous
88	   * \param indices The page indices array
89	   * \param indptr The page indptr array
90	   * \param last_page_len The offset of the last page for each request in the batch
91	   * \param rope_pos_offset The start position of each request in the batch.
92	   */
93	  __host__ __forceinline__ paged_kv_t(uint32_t num_heads, uint32_t page_size, uint32_t head_dim,
94	                                      uint32_t batch_size, QKVLayout layout, DType* k_data,
95	                                      DType* v_data, IdType* indices, IdType* indptr,
96	                                      IdType* last_page_len, IdType* rope_pos_offset = nullptr)
97	      : num_heads(num_heads),
98	        page_size(page_size),
99	        head_dim(head_dim),
100	        batch_size(batch_size),
101	        indices(indices),
102	        indptr(indptr),
103	        last_page_len(last_page_len),
104	        rope_pos_offset(rope_pos_offset) {
105	    stride_page = num_heads * page_size * head_dim;
106	    this->k_data = k_data;
107	    this->v_data = v_data;
108	    stride_n = layout == QKVLayout::kHND ? head_dim : num_heads * head_dim;
109	    stride_h = layout == QKVLayout::kHND ? page_size * head_dim : head_dim;
110	  }
111	
112	  /*!
113	   * \brief Construct a paged key-value cache with custom kv-cache strides
114	   * \param num_heads The number of heads
115	   * \param page_size The size of each page
116	   * \param head_dim The dimension of each head
117	   * \param batch_size The batch size
118	   * \param layout The layout of last 3 dimensions in KV-Cache.
119	   * \param k_data The start pointer of key cache, k_cache doesn't have to be contiguous
120	   * \param v_data The start pointer of value cache, v_cache doesn't have to be contiguous
121	   * \param kv_strides custom strides of each dimensions of k_data and v_data
122	   * \param indices The page indices array
123	   * \param indptr The page indptr array
124	   * \param last_page_len The offset of the last page for each request in the batch
125	   * \param rope_pos_offset The start position of each request in the batch.
126	   */
127	  __host__ __forceinline__ paged_kv_t(uint32_t num_heads, uint32_t page_size, uint32_t head_dim,
128	                                      uint32_t batch_size, QKVLayout layout, DType* k_data,
129	                                      DType* v_data, const int64_t* kv_strides, IdType* indices,
130	                                      IdType* indptr, IdType* last_page_len,
131	                                      IdType* rope_pos_offset = nullptr)
132	      : num_heads(num_heads),
133	        page_size(page_size),
134	        head_dim(head_dim),
135	        batch_size(batch_size),
136	        indices(indices),
137	        indptr(indptr),
138	        last_page_len(last_page_len),
139	        rope_pos_offset(rope_pos_offset) {
140	    stride_page = kv_strides[0];
141	    this->k_data = k_data;
142	    this->v_data = v_data;
143	    stride_n = layout == QKVLayout::kHND ? kv_strides[2] : kv_strides[1];
144	    stride_h = layout == QKVLayout::kHND ? kv_strides[1] : kv_strides[2];
145	  }
146	
147	  __host__ __device__ __forceinline__ uint32_t get_length(uint32_t batch_idx) const {
148	    if (indptr[batch_idx + 1] == indptr[batch_idx]) {
149	      return 0;
150	    }
151	    return (indptr[batch_idx + 1] - indptr[batch_idx] - 1) * page_size + last_page_len[batch_idx];
152	  }
153	
154	  /*!
155	   * \brief Compute the offset of element in the allocated buffer.
156	   * \param page_idx The page index
157	   * \param head_idx The head index
158	   * \param entry_idx The page entry index
159	   * \param feat_idx The feature index
160	   */
161	  __host__ __device__ __forceinline__ size_t get_elem_offset(size_t page_idx, size_t head_idx,
162	                                                             size_t entry_idx,
163	                                                             size_t feat_idx) const {
164	    return page_idx * stride_page + head_idx * stride_h + entry_idx * stride_n + feat_idx;
165	  }
166	
167	  /*!
168	   * \brief Compute the offset of element inside the page.
169	   * \param head_idx The head index
170	   * \param entry_idx The page entry index
171	   * \param feat_idx The feature index
172	   */
173	  __host__ __device__ __forceinline__ size_t get_elem_offset_in_page(size_t head_idx,
174	                                                                     size_t entry_idx,
175	                                                                     size_t feat_idx) const {
176	    return head_idx * stride_h + entry_idx * stride_n + feat_idx;
177	  }
178	
179	  __device__ __forceinline__ DType* get_k_ptr(IdType page_iter, uint32_t head_idx,
180	                                              uint32_t entry_idx, uint32_t feat_idx) const {
181	    return k_data + get_elem_offset(__ldg(indices + page_iter), head_idx, entry_idx, feat_idx);
182	  }
183	
184	  __device__ __forceinline__ size_t protective_get_kv_offset(IdType page_iter, uint32_t head_idx,
185	                                                             uint32_t entry_idx, uint32_t feat_idx,
186	                                                             IdType last_indptr) const {
187	    if (page_iter < last_indptr) {
188	      return get_elem_offset(__ldg(indices + page_iter), head_idx, entry_idx, feat_idx);
189	    } else {
190	      return 0;
191	    }
192	  }
193	
194	  __device__ __forceinline__ DType* protective_get_k_ptr(IdType page_iter, uint32_t head_idx,
195	                                                         uint32_t entry_idx, uint32_t feat_idx,
196	                                                         IdType last_indptr) const {
197	    return k_data + protective_get_kv_offset(page_iter, head_idx, entry_idx, feat_idx, last_indptr);
198	  }
199	
200	  __device__ __forceinline__ DType* get_v_ptr(IdType page_iter, uint32_t head_idx,
201	                                              uint32_t entry_idx, uint32_t feat_idx) const {
202	    return v_data + get_elem_offset(__ldg(indices + page_iter), head_idx, entry_idx, feat_idx);
203	  }
204	
205	  __device__ __forceinline__ DType* protective_get_v_ptr(IdType page_iter, uint32_t head_idx,
206	                                                         uint32_t entry_idx, uint32_t feat_idx,
207	                                                         IdType last_indptr) const {
208	    return v_data + protective_get_kv_offset(page_iter, head_idx, entry_idx, feat_idx, last_indptr);
209	  }
210	};
