212	template <typename DType>
213	__device__ __forceinline__ float nvfp4_append_to_float(DType value) {
214	  return static_cast<float>(value);
215	}
216	
217	template <>
218	__device__ __forceinline__ float nvfp4_append_to_float<nv_half>(nv_half value) {
219	  return __half2float(value);
220	}
221	
222	template <>
223	__device__ __forceinline__ float nvfp4_append_to_float<nv_bfloat16>(nv_bfloat16 value) {
224	  return __bfloat162float(value);
225	}
