227	__device__ __forceinline__ uint8_t nvfp4_append_quantize_e2m1(float value) {
228	  const uint8_t sign = signbit(value) ? 0x8 : 0x0;
229	  const float mag = fabsf(value);
230	  uint8_t code;
231	  if (!(mag > 0.25f)) {
232	    code = 0;
233	  } else if (mag < 0.75f) {
234	    code = 1;
235	  } else if (mag <= 1.25f) {
236	    code = 2;
237	  } else if (mag < 1.75f) {
238	    code = 3;
239	  } else if (mag <= 2.5f) {
240	    code = 4;
241	  } else if (mag < 3.5f) {
242	    code = 5;
243	  } else if (mag <= 5.0f) {
244	    code = 6;
245	  } else {
246	    code = 7;
247	  }
248	  return sign | code;
249	}
250	
251	template <typename DType>
252	__device__ __forceinline__ void nvfp4_append_quantize_block(
253	    const DType* __restrict__ input, const float global_scale, const size_t input_base,
254	    const uint32_t dim_base, uint8_t* __restrict__ packed_out, uint8_t* __restrict__ sf_out) {
255	  float values[16];
256	  float amax = 0.0f;
257	#pragma unroll
258	  for (uint32_t i = 0; i < 16; ++i) {
259	    const float value = nvfp4_append_to_float(input[input_base + dim_base + i]);
260	    values[i] = value;
261	    amax = fmaxf(amax, fabsf(value));
262	  }
263	
264	  float sf_value = 0.0f;
265	  if (amax > 0.0f && global_scale > 0.0f) {
266	    sf_value = amax / (6.0f * global_scale);
267	  }
268	  __nv_fp8_e4m3 sf_fp8 = __nv_fp8_e4m3(sf_value);
269	  *sf_out = sf_fp8.__x;
270	
271	  const float sf_rounded = static_cast<float>(sf_fp8);
272	  const float output_scale = (amax > 0.0f && sf_rounded > 0.0f && global_scale > 0.0f)
273	                                 ? (1.0f / (sf_rounded * global_scale))
274	                                 : 0.0f;
275	
276	#pragma unroll
277	  for (uint32_t i = 0; i < 8; ++i) {
278	    const uint8_t lo = nvfp4_append_quantize_e2m1(values[i * 2] * output_scale);
279	    const uint8_t hi = nvfp4_append_quantize_e2m1(values[i * 2 + 1] * output_scale);
280	    packed_out[i] = lo | (hi << 4);
281	  }
282	}
283	
284	__device__ __forceinline__ bool nvfp4_append_is_positive_finite_scale(float scale) {
285	  return isfinite(scale) && scale > 0.0f;
286	}
