288	/*!
289	 * \brief CUDA kernel to append new keys/values to the paged key-value cache in the decode phase
290	 * \tparam head_dim The dimension of each head
291	 * \tparam vec_size The vector size used in the kernel
292	 * \tparam DType The data type of the key-value cache
293	 * \tparam IdType The index data type of the kv-cache
294	 * \param paged_kv The paged key-value cache
295	 * \param key The key to be appended
296	 * \param value The value to be appended
297	 */
298	template <uint32_t head_dim, uint32_t vec_size, typename DType, typename IdType>
299	__global__ void AppendPagedKVCacheDecodeKernel(paged_kv_t<DType, IdType> paged_kv,
300	                                               DType* __restrict__ key, DType* __restrict__ value) {
301	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
302	  uint32_t num_heads = paged_kv.num_heads;
303	  uint32_t batch_idx = blockIdx.x;
304	  uint32_t head_idx = ty;
305	
306	  uint32_t seq_len =
307	      (paged_kv.indptr[batch_idx + 1] - paged_kv.indptr[batch_idx] - 1) * paged_kv.page_size +
308	      paged_kv.last_page_len[batch_idx];
309	
310	  uint32_t page_iter = paged_kv.indptr[batch_idx] + (seq_len - 1) / paged_kv.page_size;
311	  uint32_t entry_idx = (seq_len - 1) % paged_kv.page_size;
312	
313	  DType* k_ptr = paged_kv.get_k_ptr(page_iter, head_idx, entry_idx, tx * vec_size);
314	  DType* v_ptr = paged_kv.get_v_ptr(page_iter, head_idx, entry_idx, tx * vec_size);
315	  vec_t<DType, vec_size>::memcpy(
316	      k_ptr, key + (batch_idx * num_heads + head_idx) * head_dim + tx * vec_size);
317	
318	  vec_t<DType, vec_size>::memcpy(
319	      v_ptr, value + (batch_idx * num_heads + head_idx) * head_dim + tx * vec_size);
320	}
321	
322	/*!
323	 * \brief CUDA kernel to append new keys/values to the paged key-value cache in the prefill phase
324	 * \tparam head_dim The dimension of each head
325	 * \tparam vec_size The vector size used in the kernel
326	 * \tparam DType The data type of the key-value cache
327	 * \tparam IdType The index data type of the kv-cache
328	 * \param paged_kv The paged key-value cache
329	 * \param key The key to be appended
330	 * \param value The value to be appended
331	 * \param batch_indices The batch indices of elements to be appended
332	 * \param positions The positions of elements to be appended
333	 */
334	template <uint32_t head_dim, uint32_t vec_size, typename DType, typename IdType>
335	__global__ void AppendPagedKVCacheKernel(paged_kv_t<DType, IdType> paged_kv,
336	                                         DType* __restrict__ append_key,
337	                                         DType* __restrict__ append_value,
338	                                         IdType* __restrict__ batch_indices,
339	                                         IdType* __restrict__ positions, uint32_t nnz,
340	                                         size_t append_k_stride_n, size_t append_k_stride_h,
341	                                         size_t append_v_stride_n, size_t append_v_stride_h) {
342	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
343	  uint32_t num_heads = paged_kv.num_heads;
344	  uint32_t head_idx = ty;
345	  uint32_t cta_id = blockIdx.x;
346	  uint32_t num_ctas = gridDim.x;
347	
348	#pragma unroll 4
349	  for (uint32_t i = cta_id; i < nnz; i += num_ctas) {
350	    uint32_t page_iter, entry_idx;
351	    paged_kv.page_size.divmod(paged_kv.indptr[batch_indices[i]] * paged_kv.page_size + positions[i],
352	                              page_iter, entry_idx);
353	    DType* k_ptr = paged_kv.get_k_ptr(page_iter, head_idx, entry_idx, tx * vec_size);
354	    DType* v_ptr = paged_kv.get_v_ptr(page_iter, head_idx, entry_idx, tx * vec_size);
355	    vec_t<DType, vec_size>::memcpy(
356	        k_ptr, append_key + i * append_k_stride_n + head_idx * append_k_stride_h + tx * vec_size);
357	    vec_t<DType, vec_size>::memcpy(
358	        v_ptr, append_value + i * append_v_stride_n + head_idx * append_v_stride_h + tx * vec_size);
359	  }
360	}
361	
362	/*!
363	 * \brief Append new keys/values to the paged key-value cache in the decode phase
364	 * \tparam DType The data type of the key-value cache
365	 * \tparam IdType The index data type of the kv-cache
366	 * \param paged_kv The paged key-value cache
367	 * \param key The key to be appended
368	 * \param value The value to be appended
369	 * \param stream The CUDA stream to execute kernels.
370	 * \return status Indicates whether CUDA calls are successful
371	 */
372	template <typename DType, typename IdType>
373	cudaError_t AppendPagedKVCacheDecode(paged_kv_t<DType, IdType> paged_kv, DType* key, DType* value,
374	                                     cudaStream_t stream = nullptr) {
375	  uint32_t head_dim = paged_kv.head_dim;
376	  uint32_t batch_size = paged_kv.batch_size;
377	  uint32_t num_heads = paged_kv.num_heads;
378	  DISPATCH_HEAD_DIM(head_dim, HEAD_DIM, {
379	    constexpr uint32_t vec_size = std::max(16 / sizeof(DType), HEAD_DIM / 32);
380	    uint32_t bdx = HEAD_DIM / vec_size;
381	    uint32_t bdy = num_heads;
382	    // NOTE(Zihao): could be slow for small batch size, will optimize later
383	    dim3 nblks(batch_size);
384	    dim3 nthrs(bdx, bdy);
385	    auto kernel = AppendPagedKVCacheDecodeKernel<HEAD_DIM, vec_size, DType, IdType>;
386	    void* args[] = {(void*)&paged_kv, (void*)&key, (void*)&value};
387	    FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, 0, stream));
388	  });
389	  return cudaSuccess;
390	}
