392	/*!
393	 * \brief Append new keys/values to the paged key-value cache
394	 * \tparam layout The layout of last 3 dimension in KV-Cache
395	 * \tparam DType The data type of the key-value cache
396	 * \tparam IdType The index data type of the kv-cache
397	 * \param paged_kv The paged key-value cache
398	 * \param key The key to be appended
399	 * \param value The value to be appended
400	 * \param append_indptr The indptr array of the appended ragged tensor
401	 * \param stream The CUDA stream to execute kernels.
402	 * \return status Indicates whether CUDA calls are successful
403	 */
404	template <typename DType, typename IdType>
405	cudaError_t AppendPagedKVCache(paged_kv_t<DType, IdType> paged_kv, DType* append_key,
406	                               DType* append_value, IdType* batch_indices, IdType* positions,
407	                               uint32_t nnz, size_t append_k_stride_n, size_t append_k_stride_h,
408	                               size_t append_v_stride_n, size_t append_v_stride_h,
409	                               cudaStream_t stream = nullptr) {
410	  uint32_t head_dim = paged_kv.head_dim;
411	  uint32_t num_heads = paged_kv.num_heads;
412	  int dev_id = 0;
413	  int num_sms = 0;
414	  int num_blocks_per_sm = 0;
415	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
416	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sms, cudaDevAttrMultiProcessorCount, dev_id));
417	
418	  DISPATCH_HEAD_DIM(head_dim, HEAD_DIM, {
419	    constexpr uint32_t vec_size = std::max(16 / sizeof(DType), HEAD_DIM / 32);
420	    uint32_t bdx = HEAD_DIM / vec_size;
421	    uint32_t bdy = num_heads;
422	    uint32_t num_threads = bdx * bdy;
423	    uint32_t smem_size = 0;
424	    auto kernel = AppendPagedKVCacheKernel<HEAD_DIM, vec_size, DType, IdType>;
425	    FLASHINFER_CUDA_CALL(cudaOccupancyMaxActiveBlocksPerMultiprocessor(&num_blocks_per_sm, kernel,
426	                                                                       num_threads, smem_size));
427	    num_blocks_per_sm = min(num_blocks_per_sm, ceil_div(int(nnz), num_sms));
428	    dim3 nblks(num_blocks_per_sm * num_sms);
429	    dim3 nthrs(bdx, bdy);
430	
431	    void* args[] = {(void*)&paged_kv,          (void*)&append_key,        (void*)&append_value,
432	                    (void*)&batch_indices,     (void*)&positions,         (void*)&nnz,
433	                    (void*)&append_k_stride_n, (void*)&append_k_stride_h, (void*)&append_v_stride_n,
434	                    (void*)&append_v_stride_h};
435	    FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, 0, stream));
436	  });
437	  return cudaSuccess;
438	}
