440	template <uint32_t HEAD_DIM, typename DType, typename IdType>
441	__global__ void NVFP4QuantizeAppendPagedKVCacheKernel(
442	    paged_kv_t<uint8_t, IdType> paged_kv, const DType* __restrict__ append_key,
443	    const DType* __restrict__ append_value, const IdType* __restrict__ batch_indices,
444	    const IdType* __restrict__ positions, uint32_t nnz, size_t append_k_stride_n,
445	    size_t append_k_stride_h, size_t append_v_stride_n, size_t append_v_stride_h,
446	    uint8_t* __restrict__ k_scale_cache, uint8_t* __restrict__ v_scale_cache,
447	    size_t k_sf_stride_page, size_t k_sf_stride_n, size_t k_sf_stride_h, size_t v_sf_stride_page,
448	    size_t v_sf_stride_n, size_t v_sf_stride_h, float k_scale, float v_scale) {
449	  constexpr uint32_t SF_VEC_SIZE = 16;
450	  constexpr uint32_t PACKED_PER_SF = SF_VEC_SIZE / 2;
451	  constexpr uint32_t NUM_SF_BLOCKS = HEAD_DIM / SF_VEC_SIZE;
452	  static_assert(HEAD_DIM % SF_VEC_SIZE == 0);
453	
454	  const uint32_t token_idx = blockIdx.x;
455	  const uint32_t head_idx = blockIdx.y;
456	  if (token_idx >= nnz) return;
457	
458	  const IdType batch_idx = batch_indices[token_idx];
459	  const IdType pos = positions[token_idx];
460	  uint32_t page_iter, entry_idx;
461	  paged_kv.page_size.divmod(paged_kv.indptr[batch_idx] * paged_kv.page_size + pos, page_iter,
462	                            entry_idx);
463	  const IdType page_idx = paged_kv.indices[page_iter];
464	
465	  const size_t append_k_base =
466	      static_cast<size_t>(token_idx) * append_k_stride_n + head_idx * append_k_stride_h;
467	  const size_t append_v_base =
468	      static_cast<size_t>(token_idx) * append_v_stride_n + head_idx * append_v_stride_h;
469	  uint8_t* k_out = paged_kv.get_k_ptr(page_iter, head_idx, entry_idx, 0);
470	  uint8_t* v_out = paged_kv.get_v_ptr(page_iter, head_idx, entry_idx, 0);
471	  uint8_t* k_sf_out = k_scale_cache + static_cast<size_t>(page_idx) * k_sf_stride_page +
472	                      entry_idx * k_sf_stride_n + head_idx * k_sf_stride_h;
473	  uint8_t* v_sf_out = v_scale_cache + static_cast<size_t>(page_idx) * v_sf_stride_page +
474	                      entry_idx * v_sf_stride_n + head_idx * v_sf_stride_h;
475	
476	  for (uint32_t sf_idx = threadIdx.x; sf_idx < NUM_SF_BLOCKS * 2; sf_idx += blockDim.x) {
477	    const bool is_v = sf_idx >= NUM_SF_BLOCKS;
478	    const uint32_t block_idx = is_v ? sf_idx - NUM_SF_BLOCKS : sf_idx;
479	    const uint32_t dim_base = block_idx * SF_VEC_SIZE;
480	    const uint32_t packed_base = block_idx * PACKED_PER_SF;
481	    if (is_v) {
482	      nvfp4_append_quantize_block(append_value, v_scale, append_v_base, dim_base,
483	                                  v_out + packed_base, v_sf_out + block_idx);
484	    } else {
485	      nvfp4_append_quantize_block(append_key, k_scale, append_k_base, dim_base, k_out + packed_base,
486	                                  k_sf_out + block_idx);
487	    }
488	  }
489	}
