491	template <uint32_t HEAD_DIM, typename DType, typename IdType>
492	__global__ void NVFP4QuantizeAppendPagedKVCacheWithSlotMappingKernel(
493	    const DType* __restrict__ append_key, const DType* __restrict__ append_value,
494	    const IdType* __restrict__ slot_mapping, uint32_t nnz, uint32_t num_heads, uint32_t page_size,
495	    uint32_t max_num_pages, size_t append_k_stride_n, size_t append_k_stride_h,
496	    size_t append_v_stride_n, size_t append_v_stride_h, uint8_t* __restrict__ paged_k_cache,
497	    uint8_t* __restrict__ paged_v_cache, uint8_t* __restrict__ k_scale_cache,
498	    uint8_t* __restrict__ v_scale_cache, size_t k_stride_page, size_t k_stride_n, size_t k_stride_h,
499	    size_t v_stride_page, size_t v_stride_n, size_t v_stride_h, size_t k_sf_stride_page,
500	    size_t k_sf_stride_n, size_t k_sf_stride_h, size_t v_sf_stride_page, size_t v_sf_stride_n,
501	    size_t v_sf_stride_h, const float* __restrict__ k_scale_ptr,
502	    const float* __restrict__ v_scale_ptr) {
503	  constexpr uint32_t SF_VEC_SIZE = 16;
504	  constexpr uint32_t PACKED_PER_SF = SF_VEC_SIZE / 2;
505	  constexpr uint32_t NUM_SF_BLOCKS = HEAD_DIM / SF_VEC_SIZE;
506	  static_assert(HEAD_DIM % SF_VEC_SIZE == 0);
507	
508	  const uint32_t token_idx = blockIdx.x;
509	  const uint32_t head_idx = blockIdx.y;
510	  if (token_idx >= nnz) return;
511	
512	  const float k_scale = __ldg(k_scale_ptr);
513	  const float v_scale = __ldg(v_scale_ptr);
514	  if (!(nvfp4_append_is_positive_finite_scale(k_scale) &&
515	        nvfp4_append_is_positive_finite_scale(v_scale))) {
516	    asm volatile("trap;");
517	    return;
518	  }
519	
520	  const IdType slot = slot_mapping[token_idx];
521	  if (slot < 0 || static_cast<size_t>(slot) >= static_cast<size_t>(max_num_pages) * page_size) {
522	    return;
523	  }
524	
525	  const size_t page_idx = static_cast<size_t>(slot) / page_size;
526	  const size_t entry_idx = static_cast<size_t>(slot) % page_size;
527	  const size_t append_k_base =
528	      static_cast<size_t>(token_idx) * append_k_stride_n + head_idx * append_k_stride_h;
529	  const size_t append_v_base =
530	      static_cast<size_t>(token_idx) * append_v_stride_n + head_idx * append_v_stride_h;
531	
532	  uint8_t* k_out =
533	      paged_k_cache + page_idx * k_stride_page + entry_idx * k_stride_n + head_idx * k_stride_h;
534	  uint8_t* v_out =
535	      paged_v_cache + page_idx * v_stride_page + entry_idx * v_stride_n + head_idx * v_stride_h;
536	  uint8_t* k_sf_out = k_scale_cache + page_idx * k_sf_stride_page + entry_idx * k_sf_stride_n +
537	                      head_idx * k_sf_stride_h;
538	  uint8_t* v_sf_out = v_scale_cache + page_idx * v_sf_stride_page + entry_idx * v_sf_stride_n +
539	                      head_idx * v_sf_stride_h;
540	
541	  for (uint32_t sf_idx = threadIdx.x; sf_idx < NUM_SF_BLOCKS * 2; sf_idx += blockDim.x) {
542	    const bool is_v = sf_idx >= NUM_SF_BLOCKS;
543	    const uint32_t block_idx = is_v ? sf_idx - NUM_SF_BLOCKS : sf_idx;
544	    const uint32_t dim_base = block_idx * SF_VEC_SIZE;
545	    const uint32_t packed_base = block_idx * PACKED_PER_SF;
546	    if (is_v) {
547	      nvfp4_append_quantize_block(append_value, v_scale, append_v_base, dim_base,
548	                                  v_out + packed_base, v_sf_out + block_idx);
549	    } else {
550	      nvfp4_append_quantize_block(append_key, k_scale, append_k_base, dim_base, k_out + packed_base,
551	                                  k_sf_out + block_idx);
552	    }
553	  }
554	}
