556	template <typename DType, typename IdType>
557	cudaError_t NVFP4QuantizeAppendPagedKVCache(
558	    paged_kv_t<uint8_t, IdType> paged_kv, DType* append_key, DType* append_value,
559	    IdType* batch_indices, IdType* positions, uint32_t nnz, size_t append_k_stride_n,
560	    size_t append_k_stride_h, size_t append_v_stride_n, size_t append_v_stride_h,
561	    uint8_t* k_scale_cache, uint8_t* v_scale_cache, size_t k_sf_stride_page, size_t k_sf_stride_n,
562	    size_t k_sf_stride_h, size_t v_sf_stride_page, size_t v_sf_stride_n, size_t v_sf_stride_h,
563	    float k_scale, float v_scale, cudaStream_t stream = nullptr) {
564	  const uint32_t head_dim = paged_kv.head_dim * 2;
565	  const uint32_t num_heads = paged_kv.num_heads;
566	  if (nnz == 0 || num_heads == 0) {
567	    return cudaSuccess;
568	  }
569	  DISPATCH_HEAD_DIM(head_dim, HEAD_DIM, {
570	    constexpr uint32_t active_threads = (HEAD_DIM / 16) * 2;
571	    constexpr uint32_t num_threads =
572	        active_threads < 32 ? 32 : (active_threads > 128 ? 128 : active_threads);
573	    dim3 nblks(nnz, num_heads);
574	    dim3 nthrs(num_threads);
575	    auto kernel = NVFP4QuantizeAppendPagedKVCacheKernel<HEAD_DIM, DType, IdType>;
576	    void* args[] = {(void*)&paged_kv,          (void*)&append_key,
577	                    (void*)&append_value,      (void*)&batch_indices,
578	                    (void*)&positions,         (void*)&nnz,
579	                    (void*)&append_k_stride_n, (void*)&append_k_stride_h,
580	                    (void*)&append_v_stride_n, (void*)&append_v_stride_h,
581	                    (void*)&k_scale_cache,     (void*)&v_scale_cache,
582	                    (void*)&k_sf_stride_page,  (void*)&k_sf_stride_n,
583	                    (void*)&k_sf_stride_h,     (void*)&v_sf_stride_page,
584	                    (void*)&v_sf_stride_n,     (void*)&v_sf_stride_h,
585	                    (void*)&k_scale,           (void*)&v_scale};
586	    FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, 0, stream));
587	  });
588	  return cudaSuccess;
589	}
