646	template <typename DType, typename IdType>
647	struct paged_kv_mla_t {
648	  uint_fastdiv page_size;
649	  uint32_t head_dim_ckv;
650	  uint32_t head_dim_kpe;
651	  uint32_t batch_size;
652	  uint32_t stride_page_ckv;
653	  uint32_t stride_page_kpe;
654	  uint32_t stride_n_ckv;
655	  uint32_t stride_n_kpe;
656	
657	  // Internal layout:
658	  // [max_num_pages, page_size, head_dim]
659	  DType* ckv_data;
660	  DType* kpe_data;
661	  IdType* indices;
662	
663	  // [batch_size + 1] The page indptr array, with the first element 0, the last element nnz_pages
664	  IdType* indptr;
665	  // [batch_size] The offset of the last page for each request in the batch
666	  IdType* last_page_len;
667	  // [batch_size] The start position of each request in the batch.
668	  IdType* rope_pos_offset;
669	
670	  /*!
671	   * \brief Construct an empty paged key-value cache
672	   */
673	  __host__ __device__ __forceinline__ paged_kv_mla_t()
674	      : head_dim_ckv(0),
675	        head_dim_kpe(0),
676	        batch_size(0),
677	        stride_page_ckv(0),
678	        stride_page_kpe(0),
679	        stride_n_ckv(0),
680	        stride_n_kpe(0),
681	        ckv_data(nullptr),
682	        kpe_data(nullptr),
683	        indices(nullptr),
684	        indptr(nullptr),
685	        last_page_len(nullptr),
686	        rope_pos_offset(nullptr) {}
687	
688	  /*!
689	   * \brief Construct a paged mla kv cache
690	   * \param page_size The size of each page
691	   * \param head_dim_compressed_kv The dimension of compressed-kv
692	   * \param head_dim_kpe The dimension of k-pe
693	   * \param batch_size The batch size
694	   * \param compressed_kv_data The start pointer of compressed-kv cache, cache should be contiguous
695	   * \param kpe_data The start pointer of k-pe cache, cache should be contiguous
696	   * \param indices The page indices array
697	   * \param indptr The page indptr array
698	   * \param last_page_len The offset of the last page for each request in the batch
699	   * \param rope_pos_offset The start position of each request in the batch.
700	   */
701	  __host__ __forceinline__ paged_kv_mla_t(uint32_t page_size, uint32_t head_dim_compressed_kv,
702	                                          uint32_t head_dim_kpe, uint32_t batch_size,
703	                                          DType* compressed_kv_data, DType* kpe_data,
704	                                          IdType* indices, IdType* indptr, IdType* last_page_len,
705	                                          IdType* rope_pos_offset = nullptr)
706	      : page_size(page_size),
707	        head_dim_ckv(head_dim_compressed_kv),
708	        head_dim_kpe(head_dim_kpe),
709	        batch_size(batch_size),
710	        ckv_data(compressed_kv_data),
711	        kpe_data(kpe_data),
712	        indices(indices),
713	        indptr(indptr),
714	        last_page_len(last_page_len),
715	        rope_pos_offset(rope_pos_offset) {
716	    stride_page_ckv = page_size * head_dim_ckv;
717	    stride_n_ckv = head_dim_ckv;
718	    stride_page_kpe = page_size * head_dim_kpe;
719	    stride_n_kpe = head_dim_kpe;
720	  }
721	
722	  /*!
723	   * \brief Construct a paged key-value cache with custom kv-cache strides
724	   * \param page_size The size of each page
725	   * \param head_dim_compressed_kv The dimension of compressed-kv
726	   * \param head_dim_kpe The dimension of k-pe
727	   * \param batch_size The batch size
728	   * \param compressed_kv_data The start pointer of compressed-kv cache, cache should be contiguous
729	   * \param compressed_kv_strides custom strides of each dimensions of compressed-kv cache
730	   * \param kpe_data The start pointer of k-pe cache, cache should be contiguous
731	   * \param kpe_strides custom strides of each dimensions of k-pe cache
732	   * \param indices The page indices array
733	   * \param indptr The page indptr array
734	   * \param last_page_len The offset of the last page for each request in the batch
735	   * \param rope_pos_offset The start position of each request in the batch.
736	   */
737	  __host__ __forceinline__ paged_kv_mla_t(uint32_t page_size, uint32_t head_dim_compressed_kv,
738	                                          uint32_t head_dim_kpe, uint32_t batch_size,
739	                                          DType* compressed_kv_data,
740	                                          const int64_t* compressed_kv_strides, DType* kpe_data,
741	                                          const int64_t* kpe_strides, IdType* indices,
742	                                          IdType* indptr, IdType* last_page_len,
743	                                          IdType* rope_pos_offset = nullptr)
744	      : page_size(page_size),
745	        head_dim_ckv(head_dim_compressed_kv),
746	        head_dim_kpe(head_dim_kpe),
747	        batch_size(batch_size),
748	        ckv_data(compressed_kv_data),
749	        kpe_data(kpe_data),
750	        indices(indices),
751	        indptr(indptr),
752	        last_page_len(last_page_len),
753	        rope_pos_offset(rope_pos_offset) {
754	    stride_page_ckv = compressed_kv_strides[0];
755	    stride_n_ckv = compressed_kv_strides[1];
756	    stride_page_kpe = kpe_strides[0];
757	    stride_n_kpe = kpe_strides[1];
758	  }
759	
760	  __host__ __device__ __forceinline__ uint32_t get_length(uint32_t batch_idx) const {
761	    if (indptr[batch_idx + 1] == indptr[batch_idx]) {
762	      return 0;
763	    }
764	    return (indptr[batch_idx + 1] - indptr[batch_idx] - 1) * page_size + last_page_len[batch_idx];
765	  }
766	
767	  __host__ __device__ __forceinline__ size_t get_elem_offset_ckv(size_t page_idx, size_t entry_idx,
768	                                                                 size_t feat_idx) const {
769	    return page_idx * stride_page_ckv + entry_idx * stride_n_ckv + feat_idx;
770	  }
771	
772	  __device__ __forceinline__ size_t protective_get_offset_ckv(IdType page_iter, uint32_t entry_idx,
773	                                                              uint32_t feat_idx,
774	                                                              IdType last_indptr) const {
775	    if (page_iter < last_indptr) {
776	      return get_elem_offset_ckv(__ldg(indices + page_iter), entry_idx, feat_idx);
777	    } else {
778	      return 0;
779	    }
780	  }
781	
782	  __host__ __device__ __forceinline__ size_t get_elem_offset_kpe(size_t page_idx, size_t entry_idx,
783	                                                                 size_t feat_idx) const {
784	    return page_idx * stride_page_kpe + entry_idx * stride_n_kpe + feat_idx;
785	  }
786	
787	  __device__ __forceinline__ size_t protective_get_offset_kpe(IdType page_iter, uint32_t entry_idx,
788	                                                              uint32_t feat_idx,
789	                                                              IdType last_indptr) const {
790	    if (page_iter < last_indptr) {
791	      return get_elem_offset_kpe(__ldg(indices + page_iter), entry_idx, feat_idx);
792	    } else {
793	      return 0;
794	    }
795	  }
796	
797	  __device__ __forceinline__ DType* get_ckv_ptr(size_t page_idx, size_t entry_idx,
798	                                                size_t feat_idx) const {
799	    return ckv_data + get_elem_offset_ckv(__ldg(indices + page_idx), entry_idx, feat_idx);
800	  }
801	
802	  __device__ __forceinline__ DType* get_kpe_ptr(size_t page_idx, size_t entry_idx,
803	                                                size_t feat_idx) const {
804	    return kpe_data + get_elem_offset_kpe(__ldg(indices + page_idx), entry_idx, feat_idx);
805	  }
806	};
807	
808	template <uint32_t head_dim_ckv, uint32_t head_dim_kpe, uint32_t vec_size, typename DType,
809	          typename IdType>
810	__global__ void AppendPagedKVMlaCacheKernel(paged_kv_mla_t<DType, IdType> paged_kv_mla,
811	                                            DType* __restrict__ append_ckv,
812	                                            DType* __restrict__ append_kpe,
813	                                            IdType* __restrict__ batch_indices,
814	                                            IdType* __restrict__ positions, uint32_t nnz,
815	                                            size_t append_ckv_stride_n,
816	                                            size_t append_kpe_stride_n) {
817	  uint32_t tx = threadIdx.x;
818	  uint32_t cta_id = blockIdx.x;
819	  uint32_t num_ctas = gridDim.x;
820	
821	#pragma unroll 4
822	  for (uint32_t i = cta_id; i < nnz; i += num_ctas) {
823	    uint32_t page_iter, entry_idx;
824	    paged_kv_mla.page_size.divmod(
825	        paged_kv_mla.indptr[batch_indices[i]] * paged_kv_mla.page_size + positions[i], page_iter,
826	        entry_idx);
827	    DType* ckv_ptr = paged_kv_mla.get_ckv_ptr(page_iter, entry_idx, tx * vec_size);
828	    vec_t<DType, vec_size>::memcpy(ckv_ptr, append_ckv + i * append_ckv_stride_n + tx * vec_size);
829	
830	    if (tx * vec_size < head_dim_kpe) {
831	      DType* kpe_ptr = paged_kv_mla.get_kpe_ptr(page_iter, entry_idx, tx * vec_size);
832	      vec_t<DType, vec_size>::memcpy(kpe_ptr, append_kpe + i * append_kpe_stride_n + tx * vec_size);
833	    }
834	  }
835	}
836	
837	template <typename DType, typename IdType>
838	cudaError_t AppendPagedKVMlaCache(paged_kv_mla_t<DType, IdType> paged_kv, DType* append_ckv,
839	                                  DType* append_kpe, IdType* batch_indices, IdType* positions,
840	                                  uint32_t nnz, size_t append_ckv_stride_n,
841	                                  size_t append_kpe_stride_n, cudaStream_t stream = nullptr) {
842	  int dev_id = 0;
843	  int num_sms = 0;
844	  int num_blocks_per_sm = 0;
845	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
846	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sms, cudaDevAttrMultiProcessorCount, dev_id));
847	
848	  uint32_t head_dim_ckv = paged_kv.head_dim_ckv;
849	  uint32_t head_dim_kpe = paged_kv.head_dim_kpe;
850	  constexpr uint32_t HEAD_CKV_DIM = 512;
851	  constexpr uint32_t HEAD_KPE_DIM = 64;
852	  FLASHINFER_CHECK(head_dim_ckv == HEAD_CKV_DIM, "head_dim_ckv must be equal to 512");
853	  FLASHINFER_CHECK(head_dim_kpe == HEAD_KPE_DIM, "head_dim_kpe must be equal to 64");
854	  constexpr uint32_t vec_size = 2;
855	
856	  uint32_t bdx = HEAD_CKV_DIM / vec_size;
857	  uint32_t num_threads = bdx;
858	  uint32_t smem_size = 0;
859	  auto kernel = AppendPagedKVMlaCacheKernel<HEAD_CKV_DIM, HEAD_KPE_DIM, vec_size, DType, IdType>;
860	  FLASHINFER_CUDA_CALL(cudaOccupancyMaxActiveBlocksPerMultiprocessor(&num_blocks_per_sm, kernel,
861	                                                                     num_threads, smem_size));
862	  num_blocks_per_sm = min(num_blocks_per_sm, ceil_div(int(nnz), num_sms));
863	  dim3 nblks(num_blocks_per_sm * num_sms);
864	  dim3 nthrs(bdx);
865	  void* args[] = {(void*)&paged_kv,
866	                  (void*)&append_ckv,
867	                  (void*)&append_kpe,
868	                  (void*)&batch_indices,
869	                  (void*)&positions,
870	                  (void*)&nnz,
871	                  (void*)&append_ckv_stride_n,
872	                  (void*)&append_kpe_stride_n};
873	  FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, 0, stream));
874	  return cudaSuccess;
875	}
876	
877	}  // namespace flashinfer
878	
879	#endif  // FLAHSINFER_PAGE_CUH_
