54	  CHECK_DEVICE(append_value, append_key);
55	  CHECK_DEVICE(paged_k_cache, append_key);
56	  CHECK_DEVICE(paged_v_cache, append_key);
57	  CHECK_DEVICE(kv_indices, append_key);
58	  CHECK_DEVICE(kv_indptr, append_key);
59	  CHECK_DEVICE(kv_last_page_len, append_key);
60	
61	  QKVLayout kv_layout = QKVLayout(layout);
62	
63	  unsigned int num_heads, page_size, head_dim;
64	  head_dim = paged_k_cache.size(3);
65	  if (kv_layout == QKVLayout::kHND) {
66	    num_heads = paged_k_cache.size(1);
