92	  ffi::CUDADeviceGuard device_guard(append_key.device().device_id);
93	  const cudaStream_t stream = get_stream(append_key.device());
94	  bool success = DISPATCH_DLPACK_DTYPE_TO_CTYPE(paged_k_cache.dtype(), c_type, [&] {
95	    paged_kv_t<c_type, int32_t> paged_kv(
96	        num_heads, page_size, head_dim, batch_size, kv_layout,
97	        static_cast<c_type*>(paged_k_cache.data_ptr()),
98	        static_cast<c_type*>(paged_v_cache.data_ptr()), k_strides.data(),
99	        static_cast<int32_t*>(kv_indices.data_ptr()), static_cast<int32_t*>(kv_indptr.data_ptr()),
100	        static_cast<int32_t*>(kv_last_page_len.data_ptr()));
101	    cudaError_t status =
102	        AppendPagedKVCache(paged_kv, static_cast<c_type*>(append_key.data_ptr()),
103	                           static_cast<c_type*>(append_value.data_ptr()),
104	                           static_cast<int32_t*>(batch_indices.data_ptr()),
105	                           static_cast<int32_t*>(positions.data_ptr()), nnz, append_k_stride_n,
106	                           append_k_stride_h, append_v_stride_n, append_v_stride_h, stream);
107	    TVM_FFI_ICHECK(status == cudaSuccess)
108	        << "AppendPagedKVCache failed with error: " << cudaGetErrorString(status);
109	    return true;
110	  });
111	
112	  TVM_FFI_ICHECK(success) << "AppendPagedKVCache failed to dispatch with dtype "
113	                          << paged_k_cache.dtype();
