116	void nvfp4_quantize_append_paged_kv_cache(TensorView append_key, TensorView append_value,
117	                                          TensorView batch_indices, TensorView positions,
118	                                          TensorView paged_k_cache, TensorView paged_v_cache,
119	                                          TensorView k_scale_cache, TensorView v_scale_cache,
120	                                          TensorView kv_indices, TensorView kv_indptr,
121	                                          TensorView kv_last_page_len, double k_scale,
122	                                          double v_scale, int64_t layout) {
123	  CHECK_LAST_DIM_CONTIGUOUS(append_key);
124	  CHECK_LAST_DIM_CONTIGUOUS(append_value);
125	  CHECK_INPUT(batch_indices);
126	  CHECK_INPUT(positions);
127	  CHECK_LAST_DIM_CONTIGUOUS_INPUT(paged_k_cache);
128	  CHECK_LAST_DIM_CONTIGUOUS_INPUT(paged_v_cache);
129	  CHECK_LAST_DIM_CONTIGUOUS_INPUT(k_scale_cache);
130	  CHECK_LAST_DIM_CONTIGUOUS_INPUT(v_scale_cache);
131	  CHECK_INPUT(kv_indices);
132	  CHECK_INPUT(kv_indptr);
133	  CHECK_INPUT(kv_last_page_len);
134	  CHECK_DIM(3, append_key);
135	  CHECK_DIM(3, append_value);
136	  CHECK_DIM(1, batch_indices);
137	  CHECK_DIM(1, positions);
138	  CHECK_DIM(4, paged_k_cache);
139	  CHECK_DIM(4, paged_v_cache);
140	  CHECK_DIM(4, k_scale_cache);
141	  CHECK_DIM(4, v_scale_cache);
142	  CHECK_DIM(1, kv_indices);
143	  CHECK_DIM(1, kv_indptr);
144	  CHECK_DIM(1, kv_last_page_len);
145	  CHECK_DEVICE(append_key, append_key);
146	  CHECK_DEVICE(append_value, append_key);
147	  CHECK_DEVICE(paged_k_cache, append_key);
148	  CHECK_DEVICE(paged_v_cache, append_key);
149	  CHECK_DEVICE(k_scale_cache, append_key);
150	  CHECK_DEVICE(v_scale_cache, append_key);
151	  CHECK_DEVICE(batch_indices, append_key);
152	  CHECK_DEVICE(positions, append_key);
153	  CHECK_DEVICE(kv_indices, append_key);
154	  CHECK_DEVICE(kv_indptr, append_key);
155	  CHECK_DEVICE(kv_last_page_len, append_key);
156	
157	  TVM_FFI_ICHECK(append_key.dtype() == dl_float16 || append_key.dtype() == dl_bfloat16)
158	      << "append_key must be float16 or bfloat16";
159	  TVM_FFI_ICHECK(append_value.dtype() == append_key.dtype())
160	      << "append_key and append_value must have the same dtype";
161	  TVM_FFI_ICHECK(paged_k_cache.dtype() == dl_uint8 && paged_v_cache.dtype() == dl_uint8)
162	      << "paged_k_cache and paged_v_cache must be uint8 packed NVFP4 tensors";
163	  TVM_FFI_ICHECK(k_scale_cache.dtype() == dl_float8_e4m3fn &&
164	                 v_scale_cache.dtype() == dl_float8_e4m3fn)
165	      << "k_scale_cache and v_scale_cache must be float8_e4m3fn tensors";
166	  TVM_FFI_ICHECK(batch_indices.dtype() == dl_int32) << "batch_indices must be int32";
167	  TVM_FFI_ICHECK(positions.dtype() == dl_int32) << "positions must be int32";
168	  TVM_FFI_ICHECK(kv_indices.dtype() == dl_int32) << "kv_indices must be int32";
169	  TVM_FFI_ICHECK(kv_indptr.dtype() == dl_int32) << "kv_indptr must be int32";
170	  TVM_FFI_ICHECK(kv_last_page_len.dtype() == dl_int32) << "kv_last_page_len must be int32";
171	  TVM_FFI_ICHECK(std::isfinite(k_scale) && std::isfinite(v_scale) && k_scale > 0.0 && v_scale > 0.0)
172	      << "k_scale and v_scale must be positive finite global decode scales";
173	
174	  const unsigned int nnz = append_key.size(0);
175	  const unsigned int batch_size = kv_last_page_len.size(0);
176	  TVM_FFI_ICHECK_EQ(kv_indptr.size(0), batch_size + 1);
177	  TVM_FFI_ICHECK_EQ(batch_indices.size(0), nnz);
178	  TVM_FFI_ICHECK_EQ(positions.size(0), nnz);
179	
180	  QKVLayout kv_layout = QKVLayout(layout);
181	  unsigned int num_heads, page_size;
182	  const unsigned int packed_head_dim = paged_k_cache.size(3);
183	  const unsigned int scale_dim = k_scale_cache.size(3);
184	  const unsigned int head_dim = append_key.size(2);
185	  if (kv_layout == QKVLayout::kHND) {
186	    num_heads = paged_k_cache.size(1);
187	    page_size = paged_k_cache.size(2);
188	  } else {
189	    page_size = paged_k_cache.size(1);
190	    num_heads = paged_k_cache.size(2);
191	  }
192	
193	  TVM_FFI_ICHECK_EQ(append_key.size(1), num_heads);
194	  TVM_FFI_ICHECK_EQ(append_value.size(0), nnz);
195	  TVM_FFI_ICHECK_EQ(append_value.size(1), num_heads);
196	  TVM_FFI_ICHECK_EQ(append_value.size(2), head_dim);
197	  TVM_FFI_ICHECK_EQ(packed_head_dim * 2, head_dim);
198	  TVM_FFI_ICHECK_EQ(scale_dim * 16, head_dim);
199	  TVM_FFI_ICHECK_EQ(head_dim % 16, 0);
200	
201	  auto require_same_shape = [](TensorView lhs, TensorView rhs, const char* name) {
202	    TVM_FFI_ICHECK_EQ(lhs.ndim(), rhs.ndim()) << name << " ndim mismatch";
203	    for (int i = 0; i < lhs.ndim(); ++i) {
204	      TVM_FFI_ICHECK_EQ(lhs.size(i), rhs.size(i)) << name << " shape mismatch at dim " << i;
205	    }
206	  };
207	  require_same_shape(paged_k_cache, paged_v_cache, "paged K/V cache");
208	  require_same_shape(k_scale_cache, v_scale_cache, "K/V scale cache");
209	  TVM_FFI_ICHECK_EQ(k_scale_cache.size(0), paged_k_cache.size(0));
210	  if (kv_layout == QKVLayout::kHND) {
211	    TVM_FFI_ICHECK_EQ(k_scale_cache.size(1), num_heads);
212	    TVM_FFI_ICHECK_EQ(k_scale_cache.size(2), page_size);
213	  } else {
214	    TVM_FFI_ICHECK_EQ(k_scale_cache.size(1), page_size);
215	    TVM_FFI_ICHECK_EQ(k_scale_cache.size(2), num_heads);
216	  }
217	
218	  auto k_strides = paged_k_cache.strides();
219	  auto v_strides = paged_v_cache.strides();
220	  auto k_dim = paged_k_cache.ndim();
221	  TVM_FFI_ICHECK(std::equal(k_strides.begin(), k_strides.begin() + k_dim, v_strides.begin()))
222	      << "packed k/v strides must be identical";
223	  auto k_sf_strides = k_scale_cache.strides();
224	  auto v_sf_strides = v_scale_cache.strides();
225	  auto sf_dim = k_scale_cache.ndim();
226	  TVM_FFI_ICHECK(
227	      std::equal(k_sf_strides.begin(), k_sf_strides.begin() + sf_dim, v_sf_strides.begin()))
228	      << "scale k/v strides must be identical";
229	
230	  const size_t k_sf_stride_page = k_sf_strides[0];
231	  const size_t k_sf_stride_n = kv_layout == QKVLayout::kHND ? k_sf_strides[2] : k_sf_strides[1];
232	  const size_t k_sf_stride_h = kv_layout == QKVLayout::kHND ? k_sf_strides[1] : k_sf_strides[2];
233	  const size_t v_sf_stride_page = v_sf_strides[0];
234	  const size_t v_sf_stride_n = kv_layout == QKVLayout::kHND ? v_sf_strides[2] : v_sf_strides[1];
235	  const size_t v_sf_stride_h = kv_layout == QKVLayout::kHND ? v_sf_strides[1] : v_sf_strides[2];
236	  auto append_k_strides = append_key.strides();
237	  auto append_v_strides = append_value.strides();
238	  const size_t append_k_stride_n = append_k_strides[0];
239	  const size_t append_k_stride_h = append_k_strides[1];
240	  const size_t append_v_stride_n = append_v_strides[0];
241	  const size_t append_v_stride_h = append_v_strides[1];
242	
243	  ffi::CUDADeviceGuard device_guard(append_key.device().device_id);
244	  const cudaStream_t stream = get_stream(append_key.device());
245	  bool success = DISPATCH_DLPACK_DTYPE_TO_CTYPE_FP16(append_key.dtype(), c_type, [&] {
246	    paged_kv_t<uint8_t, int32_t> paged_kv(
247	        num_heads, page_size, packed_head_dim, batch_size, kv_layout,
248	        static_cast<uint8_t*>(paged_k_cache.data_ptr()),
249	        static_cast<uint8_t*>(paged_v_cache.data_ptr()), k_strides.data(),
250	        static_cast<int32_t*>(kv_indices.data_ptr()), static_cast<int32_t*>(kv_indptr.data_ptr()),
251	        static_cast<int32_t*>(kv_last_page_len.data_ptr()));
252	    cudaError_t status = NVFP4QuantizeAppendPagedKVCache(
253	        paged_kv, static_cast<c_type*>(append_key.data_ptr()),
254	        static_cast<c_type*>(append_value.data_ptr()),
255	        static_cast<int32_t*>(batch_indices.data_ptr()),
256	        static_cast<int32_t*>(positions.data_ptr()), nnz, append_k_stride_n, append_k_stride_h,
257	        append_v_stride_n, append_v_stride_h, static_cast<uint8_t*>(k_scale_cache.data_ptr()),
258	        static_cast<uint8_t*>(v_scale_cache.data_ptr()), k_sf_stride_page, k_sf_stride_n,
259	        k_sf_stride_h, v_sf_stride_page, v_sf_stride_n, v_sf_stride_h, static_cast<float>(k_scale),
260	        static_cast<float>(v_scale), stream);
261	    TVM_FFI_ICHECK(status == cudaSuccess)
262	        << "NVFP4QuantizeAppendPagedKVCache failed with error: " << cudaGetErrorString(status);
263	    return true;
264	  });
265	
266	  TVM_FFI_ICHECK(success) << "NVFP4QuantizeAppendPagedKVCache failed to dispatch with dtype "
267	                          << append_key.dtype();
268	}
