440	  CHECK_DEVICE(ckv_cache, append_ckv);
441	
442	  CHECK_DEVICE(kv_indices, append_ckv);
443	  CHECK_DEVICE(kv_indptr, append_ckv);
444	  CHECK_DEVICE(kv_last_page_len, append_ckv);
445	
446	  unsigned int page_size, ckv_dim, kpe_dim;
447	  page_size = ckv_cache.size(1);
448	  ckv_dim = ckv_cache.size(2);
449	  kpe_dim = kpe_cache.size(2);
450	
451	  // get kv_cache_strides
452	  auto ckv_strides = ckv_cache.strides();
453	  auto kpe_strides = kpe_cache.strides();
454	
455	  auto append_ckv_strides = append_ckv.strides();
456	  auto append_ckv_stride_n = append_ckv_strides[0];
457	  auto append_kpe_strides = append_kpe.strides();
458	  auto append_kpe_stride_n = append_kpe_strides[0];
459	
460	  TVM_FFI_ICHECK_EQ(append_ckv.size(1), ckv_dim);
461	  TVM_FFI_ICHECK_EQ(append_kpe.size(1), kpe_dim);
462	
463	  ffi::CUDADeviceGuard device_guard(append_ckv.device().device_id);
464	  const cudaStream_t stream = get_stream(append_ckv.device());
465	  bool success = DISPATCH_DLPACK_DTYPE_TO_CTYPE(ckv_cache.dtype(), c_type, [&] {
466	    paged_kv_mla_t<c_type, int32_t> paged_mla_kv(
467	        page_size, ckv_dim, kpe_dim, batch_size, static_cast<c_type*>(ckv_cache.data_ptr()),
468	        ckv_strides.data(), static_cast<c_type*>(kpe_cache.data_ptr()), kpe_strides.data(),
469	        static_cast<int32_t*>(kv_indices.data_ptr()), static_cast<int32_t*>(kv_indptr.data_ptr()),
470	        static_cast<int32_t*>(kv_last_page_len.data_ptr()));
471	    cudaError_t status =
472	        AppendPagedKVMlaCache(paged_mla_kv, static_cast<c_type*>(append_ckv.data_ptr()),
473	                              static_cast<c_type*>(append_kpe.data_ptr()),
474	                              static_cast<int32_t*>(batch_indices.data_ptr()),
475	                              static_cast<int32_t*>(positions.data_ptr()), nnz, append_ckv_stride_n,
476	                              append_kpe_stride_n, stream);
477	    TVM_FFI_ICHECK(status == cudaSuccess)
478	        << "AppendPagedKVMlaCache failed with error: " << cudaGetErrorString(status);
479	    return true;
480	  });
481	
482	  TVM_FFI_ICHECK(success) << "AppendPagedKVMlaCache failed to dispatch with dtype "
483	                          << ckv_cache.dtype();
484	}
